import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.DTQlDYOH.js";const u=JSON.parse('{"title":"Introduction to B.A.G.E.L.","description":"","frontmatter":{},"headers":[],"relativePath":"intro.md","filePath":"intro.md"}'),r={name:"intro.md"};function i(s,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction-to-b-a-g-e-l" tabindex="-1">Introduction to B.A.G.E.L. <a class="header-anchor" href="#introduction-to-b-a-g-e-l" aria-label="Permalink to &quot;Introduction to B.A.G.E.L.&quot;">​</a></h1><p><strong>B.A.G.E.L.</strong> (Board-based Automated Game Engine Language) is a JSON-based declarative language for defining board and card games. You describe entities (boards, pieces, cards), moves, turn structure, and end conditions in a single JSON object. A runtime interprets that definition and runs the game.</p><h2 id="how-it-fits-together" tabindex="-1">How it fits together <a class="header-anchor" href="#how-it-fits-together" aria-label="Permalink to &quot;How it fits together&quot;">​</a></h2><ol><li><strong>You write</strong> a B.A.G.E.L. game definition (JSON).</li><li><strong>The editor</strong> in this app lets you edit and test definitions live.</li><li><strong>The <a href="https://www.npmjs.com/package/board-game-engine" target="_blank" rel="noreferrer">board-game-engine</a></strong> npm package expands and normalizes the JSON, then produces a <a href="https://boardgame.io/" target="_blank" rel="noreferrer">boardgame.io</a>-compatible game.</li><li><strong>The game</strong> runs in the browser (or on a server) using that engine.</li></ol><p>Example games (tic-tac-toe, Connect Four, Reversi, Checkers, Eights) are included in this project under <code>server/</code> and can be loaded in the editor.</p><h2 id="what-you-can-define" tabindex="-1">What you can define <a class="header-anchor" href="#what-you-can-define" aria-label="Permalink to &quot;What you can define&quot;">​</a></h2><ul><li><strong>Entities</strong> — Grids, spaces, pieces, cards (with optional state like “isKing” or “player”).</li><li><strong>Boards</strong> — Which entities form the shared board and, optionally, each player’s personal board (e.g. hand, score).</li><li><strong>Moves</strong> — Place new pieces, move or remove entities, take from stacks, change state, end or pass turns, run follow-up moves.</li><li><strong>Turns</strong> — Min/max moves per turn, optional stages (e.g. “must jump if possible” then “move or king”).</li><li><strong>End conditions</strong> — Win/draw when a line appears, board is full, or a custom expression is true.</li></ul><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><p>Go to <a href="./getting-started.html">Getting started</a> to see a minimal example and run it in the editor.</p>',9)])])}const p=t(r,[["render",i]]);export{u as __pageData,p as default};
